import Redis from 'ioredis';
import { getSecret } from './secrets';

let client: Redis | null = null;
let currentHost: string | null = null;

export async function getRedis(): Promise<Redis> {
  const cfg = await getSecret<{host:string; port:number; auth_token:string; tls:boolean}>('prod/redis/url');
  if (client && currentHost === cfg.host) return client;

  if (client && currentHost !== cfg.host) {
    const old = client;
    setTimeout(() => old.quit().catch(()=>{}), 30_000);
  }

  client = new Redis({
    host: cfg.host,
    port: cfg.port,
    password: cfg.auth_token,
    tls: cfg.tls ? {} : undefined,
    connectTimeout: 10_000,
    maxRetriesPerRequest: 5,
    retryStrategy: (times) => Math.min(times * 200, 3000),
    reconnectOnError: (err) => {
      const targetErrors = ['READONLY', 'ETIMEDOUT', 'ECONNRESET'];
      return targetErrors.some(e => err.message.includes(e));
    },
    enableAutoPipelining: true,
  });
  currentHost = cfg.host;
  return client;
}

