package provider

import (
	"context"
	"github.com/hashicorp/terraform-plugin-framework/resource"
	"github.com/hashicorp/terraform-plugin-framework/resource/schema"
	"github.com/hashicorp/terraform-plugin-framework/types"
)

type ServiceResource struct {
	client *Client
}

type ServiceResourceModel struct {
	ID    types.String `tfsdk:"id"`
	Name  types.String `tfsdk:"name"`
	Tier  types.String `tfsdk:"tier"`
	Owner types.String `tfsdk:"owner"`
}

func (r *ServiceResource) Schema(_ context.Context, _ resource.SchemaRequest, resp *resource.SchemaResponse) {
	resp.Schema = schema.Schema{
		Attributes: map[string]schema.Attribute{
			"id":    schema.StringAttribute{Computed: true},
			"name":  schema.StringAttribute{Required: true},
			"tier":  schema.StringAttribute{Required: true, Validators: []validator.String{stringvalidator.OneOf("1", "2", "3")}},
			"owner": schema.StringAttribute{Required: true},
		},
	}
}

func (r *ServiceResource) Create(ctx context.Context, req resource.CreateRequest, resp *resource.CreateResponse) {
	var plan ServiceResourceModel
	resp.Diagnostics.Append(req.Plan.Get(ctx, &plan)...)
	if resp.Diagnostics.HasError() { return }
	created, err := r.client.CreateService(ServiceAPI{Name: plan.Name.ValueString(), Tier: plan.Tier.ValueString(), Owner: plan.Owner.ValueString()})
	if err != nil { resp.Diagnostics.AddError("API error", err.Error()); return }
	plan.ID = types.StringValue(created.ID)
	resp.Diagnostics.Append(resp.State.Set(ctx, plan)...)
}

func (r *ServiceResource) Read(ctx context.Context, req resource.ReadRequest, resp *resource.ReadResponse) {
	var state ServiceResourceModel
	resp.Diagnostics.Append(req.State.Get(ctx, &state)...)
	if resp.Diagnostics.HasError() { return }
	actual, err := r.client.GetService(state.ID.ValueString())
	if err != nil {
		if IsNotFound(err) { resp.State.RemoveResource(ctx); return }
		resp.Diagnostics.AddError("API error", err.Error()); return
	}
	state.Name = types.StringValue(actual.Name)
	state.Tier = types.StringValue(actual.Tier)
	state.Owner = types.StringValue(actual.Owner)
	resp.Diagnostics.Append(resp.State.Set(ctx, state)...)
}

