import { Pool } from 'pg';
import { getSecret } from './secrets';

let writePool: Pool | null = null;
let readPool: Pool | null = null;

export async function getWritePool() {
  if (writePool) return writePool;
  const cfg = await getSecret('prod/pg/primary');
  writePool = new Pool({ ...cfg, max: 10 });
  return writePool;
}

export async function getReadPool() {
  if (readPool) return readPool;
  const cfg = await getSecret('prod/pg/replica');
  readPool = new Pool({ ...cfg, max: 5 });
  return readPool;
}

export async function query(sql: string, params: any[] = [], opts: { write?: boolean } = {}) {
  const pool = opts.write ? await getWritePool() : await getReadPool();
  return pool.query(sql, params);
}

