resource "aws_iam_role" "gha_per_repo" {
  for_each = toset(var.allowed_repos)
  name = "gha-${each.value}"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Effect = "Allow"
      Principal = { Federated = aws_iam_openid_connect_provider.github.arn }
      Action = "sts:AssumeRoleWithWebIdentity"
      Condition = {
        StringEquals = { "token.actions.githubusercontent.com:aud": "sts.amazonaws.com" }
        StringLike = {
          "token.actions.githubusercontent.com:sub": [
            "repo:acme/${each.value}:ref:refs/heads/main",
            "repo:acme/${each.value}:environment:${var.env_name}"
          ]
        }
      }
    }]
  })
}

import http from 'k6/http';
import { check, sleep } from 'k6';

export const options = {
  vus: 1,
  iterations: 1,
  thresholds: {
    http_req_duration: ['p(95)<2000'],
    http_req_failed: ['rate<0.01'],
  },
};

export default function() {
  const loginRes = http.post('https://api.acme.com/api/auth/login', JSON.stringify({
    email: __ENV.PROBE_EMAIL,
    password: __ENV.PROBE_PASSWORD,
  }), { headers: {'Content-Type': 'application/json'}});
  check(loginRes, {
    'login 200': r => r.status === 200,
    'token returned': r => r.json('token') !== undefined,
  });
  if (loginRes.status !== 200) return;

  const token = loginRes.json('token');
  const profile = http.get('https://api.acme.com/api/me', {
    headers: {'Authorization': `Bearer ${token}`},
  });
  check(profile, { 'profile 200': r => r.status === 200 });
}

